// Get current user and all events
const user = $input.item.json.users;
const allEvents = $input.item.json.events;

// If no events today, skip
if (!allEvents || allEvents.length === 0) {
  return { json: { skip: true, phone: user.phone } };
}

// Randomly select 3-4 events (or all if less than 3)
const numToSelect = Math.min(allEvents.length, Math.floor(Math.random() * 2) + 3); // 3 or 4
const shuffled = allEvents.sort(() => 0.5 - Math.random());
const selectedEvents = shuffled.slice(0, numToSelect);

// Format for AI prompt
const eventsText = selectedEvents.map((e, idx) => 
  `${idx + 1}. **${e.json.name}** at ${e.json.time}\n   ${e.json.description}\n   📍 ${e.json.location}`
).join('\n\n');

const totalEvents = allEvents.length;

return {
  json: {
    phone: user.phone,
    name: user.name,
    eventsText: eventsText,
    totalEvents: totalEvents,
    selectedCount: selectedEvents.length,
    selectedEventIds: selectedEvents.map(e => e.json.id),
    skip: false
  }
};

// Extract AI-generated message
const aiResponse = $input.first().json;
const hypeMessage = aiResponse.choices?.[0]?.message?.content || aiResponse.text || aiResponse.message?.content || '';

// Get user data from previous node
const userData = $('Select Random Events').first().json;

// Create payload for notification
const payload = {
  user_name: userData.name,
  hype_message: hypeMessage,
  event_ids: userData.selectedEventIds,
  total_events: userData.totalEvents
};

// Schedule times: 9am, 12pm, 3pm, 6pm (various times throughout the day)
const scheduleTimes = ['09:00:00', '12:00:00', '15:00:00', '18:00:00'];
const randomTime = scheduleTimes[Math.floor(Math.random() * scheduleTimes.length)];

const scheduledAt = `CURRENT_DATE + TIME '${randomTime}'`;

return {
  json: {
    phone: userData.phone,
    template: 'HYPE',
    payload: JSON.stringify(payload),
    scheduled_at_expr: scheduledAt,
    hype_message: hypeMessage
  }
};

const totalInserted = $input.all().length;
const firstPhone = $input.first().json.phone || 'N/A';
const lastPhone = $input.last().json.phone || 'N/A';

return {
  json: {
    success: true,
    total_notifications: totalInserted,
    first_user: firstPhone,
    last_user: lastPhone,
    timestamp: new Date().toISOString()
  }
};
